inline KoopmanWeights make_koopman_weights() {
    KoopmanWeights w{};
    w.proj_weight = koopman_weights_data::proj_weight;
    w.proj_bias = koopman_weights_data::proj_bias;
    w.CA = koopman_weights_data::CA;
    w.F = koopman_weights_data::F;
    w.s_max = koopman_weights_data::s_max;
    return w;
}

inline const KoopmanWeights g_koopman_weights = make_koopman_weights();

